import xml.etree.ElementTree as ET

def parse_xml_config(filepath):
    config = {}
    tree = ET.parse(filepath)
    root = tree.getroot()

    for child in root:
        if len(child) == 0:  # Leaf element
            if child.text is not None:
                config[child.tag] = child.text.strip()
            else:
                config[child.tag] = None
        else:  # Parent element with children
            sub_config = {}
            for sub_child in child:
                if len(sub_child) == 0:
                    if sub_child.text is not None:
                        sub_config[sub_child.tag] = sub_child.text.strip()
                    else:
                        sub_config[sub_child.tag] = None
                else:
                    # Handle nested structures more deeply if needed,
                    # for this example, we'll convert inner-most simple structures
                    # and leave more complex ones to further recursion/logic
                    # For simplicity, if a sub_child has children, it's treated as a string for now,
                    # or could be expanded to a recursive call to parse_xml_config_element(sub_child)
                    sub_sub_config = {}
                    for item in sub_child:
                        if item.text is not None:
                            sub_sub_config[item.tag] = item.text.strip()
                        else:
                            sub_sub_config[item.tag] = None
                    if sub_sub_config:
                        sub_config[sub_child.tag] = sub_sub_config
                    elif sub_child.text is not None:
                        sub_config[sub_child.tag] = sub_child.text.strip()
                    else:
                        sub_config[sub_child.tag] = None

            config[child.tag] = sub_config
    return config